+import {Options, RuleType} from '../rules';
+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+import dedent from 'ts-dedent';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: number = 2;
+  minLevel: number = 2;
+  maxLevel: number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = {level: number, text: string, anchor: string};
+
+const tocStart = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const tocEnd = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const atxHeading = /^ {0,3}(#{1,6})(?:[ \	]+|$)(.*)$/;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const lines = text.split('\
');
+    const startIndex = lines.findIndex((line) => tocStart.test(line));
+    if (startIndex === -1) return text;
+
+    const foundEndIndex = lines.findIndex((line, index) => index > startIndex && tocEnd.test(line));
+    // A missing end marker means the TOC has no existing body to replace. Insert one
+    // directly after the generated TOC so subsequent document headings remain visible.
+    const endIndex = foundEndIndex === -1 ? startIndex : foundEndIndex;
+    const headings = this.getHeadings(lines, startIndex, endIndex, options);
+    const tocLines = this.makeToc(lines[startIndex], foundEndIndex === -1 ? '<!-- /toc -->' : lines[foundEndIndex], headings, options);
+
+    if (foundEndIndex === -1) {
+      lines.splice(startIndex, 1, ...tocLines);
+    } else {
+      lines.splice(startIndex, foundEndIndex - startIndex + 1, ...tocLines);
+    }
+    return lines.join('\
');
+  }
+
+  private getHeadings(lines: string[], tocStartIndex: number, tocEndIndex: number, options: AutoTocOptions): Heading[] {
+    const headings: Heading[] = [];
+    const anchors = new Map<string, number>();
+    let inYaml = false;
+    let inCodeFence = false;
+    let inMath = false;
+
+    for (let index = 0; index < lines.length; index++) {
+      const line = lines[index];
+      if (index === 0 && /^---\\s*$/.test(line)) {
+        inYaml = true;
+        continue;
+      }
+      if (inYaml) {
+        if (/^(---|\\.\\.\\.)\\s*$/.test(line)) inYaml = false;
+        continue;
+      }
+      if (/^ {0,3}(`{3,}|~{3,})/.test(line)) {
+        inCodeFence = !inCodeFence;
+        continue;
+      }
+      if (inCodeFence) continue;
+      if (/^\\s*\\$\\$\\s*$/.test(line)) {
+        inMath = !inMath;
+        continue;
+      }
+      if (inMath || (index > tocStartIndex && index < tocEndIndex)) continue;
+
+      const match = line.match(atxHeading);
+      if (!match) continue;
+      const level = match[1].length;
+      if (level < options.minLevel || level > options.maxLevel) continue;
+      const text = stripClosingHashes(match[2]);
+      if (isExcluded(text, options.excludeHeadings)) continue;
+
+      const explicitId = options.useExplicitIds ? text.match(/\\s*\\{#([^}\\s]+)\\}\\s*$/)?.[1] : undefined;
+      const visibleText = explicitId ? text.replace(/\\s*\\{#[^}\\s]+\\}\\s*$/, '') : text;
+      const baseAnchor = explicitId ?? createAnchor(visibleText);
+      const count = anchors.get(baseAnchor) ?? 0;
+      anchors.set(baseAnchor, count + 1);
+      headings.push({level, text: options.stripFormattingInToc ? stripFormatting(visibleText) : resolveLinks(visibleText), anchor: count === 0 ? baseAnchor : `${baseAnchor}-${count}`});
+    }
+    return headings;
+  }
+
+  private makeToc(startMarker: string, endMarker: string, headings: Heading[], options: AutoTocOptions): string[] {
+    const items = headings.map((heading, index) => {
+      const indent = ' '.repeat(Math.max(0, heading.level - options.minLevel) * options.indentSize);
+      const marker = options.listStyle === 'bullet' ? options.bulletMarker : `${options.orderedListStyle === 'increment' ? index + 1 : 1}.`;
+      return `${indent}${marker} [${heading.text}](#${heading.anchor})`;
+    });
+    return [startMarker, '', ...(options.title ? [options.title, ''] : []), ...items, '', endMarker, ''];
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [new ExampleBuilder({
+      description: 'Generates a table of contents at a toc marker',
+      before: dedent`
+        # Document
+        <!-- toc -->
+        <!-- /toc -->
+        ## First section
+        ### Nested section
+      `,
+      after: dedent`
+        # Document
+        <!-- toc -->
+
+        - [First section](#first-section)
+          - [Nested section](#nested-section)
+
+        <!-- /toc -->
+
+        ## First section
+        ### Nested section
+      `,
+    })];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [
+      new DropdownOptionBuilder<AutoTocOptions, ListStyle>({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.list-style.name', descriptionKey: 'rules.auto-toc.list-style.description', optionsKey: 'listStyle', records: [{value: 'bullet', description: 'Bullet list'}, {value: 'number', description: 'Numbered list'}]}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.bullet-marker.name', descriptionKey: 'rules.auto-toc.bullet-marker.description', optionsKey: 'bulletMarker'}),
+      new DropdownOptionBuilder<AutoTocOptions, OrderedListStyle>({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.ordered-list-style.name', descriptionKey: 'rules.auto-toc.ordered-list-style.description', optionsKey: 'orderedListStyle', records: [{value: 'always-one', description: 'Always use 1'}, {value: 'increment', description: 'Increment'}]}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.indent-size.name', descriptionKey: 'rules.auto-toc.indent-size.description', optionsKey: 'indentSize'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.min-level.name', descriptionKey: 'rules.auto-toc.min-level.description', optionsKey: 'minLevel'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.max-level.name', descriptionKey: 'rules.auto-toc.max-level.description', optionsKey: 'maxLevel'}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.title.name', descriptionKey: 'rules.auto-toc.title.description', optionsKey: 'title'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.use-explicit-ids.name', descriptionKey: 'rules.auto-toc.use-explicit-ids.description', optionsKey: 'useExplicitIds'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.strip-formatting-in-toc.name', descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description', optionsKey: 'stripFormattingInToc'}),
+      new TextAreaOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.exclude-headings.name', descriptionKey: 'rules.auto-toc.exclude-headings.description', optionsKey: 'excludeHeadings'}),
+    ];
+  }
+}
+
+function stripClosingHashes(text: string): string {
+  return text.replace(/[ \	]+#+[ \	]*$/, '').trim();
+}
+
+function resolveLinks(text: string): string {
+  return text
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)\\|([^\\]]+)\\]\\]/g, '$2')
+      .replace(/\\[\\[([^\\]]+)\\]\\]/g, '$1')
+      .replace(/\\[([^\\]]+)\\]\\([^)]*\\)/g, '$1');
+}
+
+function stripFormatting(text: string): string {
+  return resolveLinks(text)
+      .replace(/`([^`]+)`/g, '$1')
+      .replace(/(\\*\\*|__)(.*?)\\1/g, '$2')
+      .replace(/(\\*|_)(.*?)\\1/g, '$2')
+      .replace(/~~(.*?)~~/g, '$1')
+      .replace(/<[^>]+>/g, '')
+      .trim();
+}
+
+function createAnchor(text: string): string {
+  return stripFormatting(text)
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9_-]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+}
+
+function isExcluded(text: string, exclusions: string[]): boolean {
+  const comparable = stripFormatting(text);
+  return exclusions.some((exclusion) => {
+    if (exclusion.startsWith('/') && exclusion.endsWith('/') && exclusion.length > 2) {
+      try {
+        return new RegExp(exclusion.slice(1, -1), 'i').test(comparable);
+      } catch (_) {
+        return false;
+      }
+    }
+    return exclusion.toLowerCase() === comparable.toLowerCase();
+  });
+}
